import json
from smolagents import ToolAgent
from jsonschema import validate, ValidationError

expected_schema = {
    "type": "object",
    "properties": {
        "result": {"type": "number"},
        "steps": {"type": "array"}
    },
    "required": ["result", "steps"]
}

def detect_schema_consistency(agent, input_text, runs=3):
    failures = 0
    for i in range(runs):
        try:
            result = agent.run(input_text)
            validate(instance=result, schema=expected_schema)
        except (ValidationError, AttributeError):
            failures += 1
            print(f"Run {i+1} failed schema validation")

    consistency_rate = 1 - (failures / runs)
    print(f"Schema consistency: {consistency_rate:.2f}")
    return consistency_rate < 0.8

# Usage
tool_agent = ToolAgent(tools=[...])
detect_schema_consistency(tool_agent, "Calculate area of 5x7 rectangle")

