from smolagents import CodeAgent

def self_critiquing_agent(input_text, max_retries=3):
    agent = CodeAgent()

    for attempt in range(max_retries):
        result = agent.run(f"""
        Solve: {input_text}
        Previous attempts {'failed consistency checks' if attempt > 0 else 'N/A'}
        Return ONLY the final numerical answer as JSON: {{"answer": 123}}
        """)

        # Extract and validate
        try:
            parsed = json.loads(str(result))
            if isinstance(parsed.get('answer'), (int, float)):
                return parsed['answer']
        except:
            pass

        print(f"Retry {attempt + 1}/{max_retries}")

    raise ValueError("Failed to produce consistent output")

# Usage
answer = self_critiquing_agent("25 * 8 / 5")

from smolagents import CodeAgent
from collections import Counter
import json

def ensemble_agent(input_text, num_agents=5):
    agents = [CodeAgent() for _ in range(num_agents)]
    answers = []

    for i, agent in enumerate(agents):
        try:
            result = agent.run(f"""
            Solve precisely: {input_text}
            Return ONLY: {{ "answer": 123.45 }}
            """)
            parsed = json.loads(str(result))
            answers.append(parsed.get('answer'))
        except:
            pass

    # Vote on most common answer
    vote = Counter(answers).most_common(1)
    if vote:
        return vote[0][0]
    return None

# Usage
final_answer = ensemble_agent("What is 15 * 8?")

