from smolagents import CodeAgent
import vex

@vex.verify(
    checks=[
        vex.consistency.runs(5, similarity_threshold=0.85),
        vex.schema.validate({
            "type": "object",
            "properties": {"result": {"type": "number"}}
        }),
        vex.security.no_eval_code()
    ],
    retry_on_fail=2,
    alert_on_fail=True
)
def reliable_math_agent(prompt: str) -> float:
    agent = CodeAgent()
    result = agent.run(prompt)
    return float(str(result))

# Production usage
answer = reliable_math_agent("Calculate 25 * 8")
print(f"Verified answer: {answer}")
